type NationalTierNeedItem = {
    typeId: string;
    amount: number;
};

type NationalTierNeed = {
    item: NationalTierNeedItem[];
    point: number;
};

type NationalTierContinuationItem = {
    level: number;
    item: NationalTierNeedItem[];
};

const getNationalTierPoint = (level: number) => {
    const tier = Math.ceil(level / 5);
    return level % 5 === 0 ? tier * 500 : tier * 100;
};

